 */
async function forwardToWeatherBotHandler(update) {
  try {
    // Escape single quotes for shell: ' becomes '"'"'
    const updateJson = JSON.stringify(update).replace(/'/g, "'\"'\"'");

    const { stdout, stderr } = await execAsync(
